import React, { useMemo } from 'react';
import { Button, Checkbox, Input, Modal, SearchInput, Select } from '@linm-soft-org/linm-web-common-components';
import {
  CustomerSearchField,
  AccountSearchInput,
  ContractSearchField,
  CustomerTypeBadge,
  createAccountSearchConfig,
  useAccountSearchAsOfDate,
} from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import {
  CurrencyPairField,
  useVoucherHeaderCompact,
  VoucherDescriptionField,
  VoucherFormRow,
  RequiredMark,
} from '../../../../../components/voucher';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import { formatPartnerFieldLabel } from '../../../../../constants/partnerFieldLabels';
import styles from '../../../../../styles/documentForm.module.css';
import layout from '../styles/cashVoucherHeaderLayout.module.css';

export const CashVoucherHeaderSection: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const {
    kind,
    labels,
    receiptKind,
    setReceiptKind,
    receiptKindOpts,
    receiptKindLocked,
    setReceiptKindPendingChange,
    setShowReceiptKindConfirm,
    tid,
    viewSectionClass,
    voucherDate,
    setVoucherDate,
    patchHeaderFieldError,
    fieldErrors,
    fieldLockProps,
    voucherNumber,
    ph,
    staticFieldProps,
    fmLegacyCode,
    currencyCode,
    currencyOptions,
    exchangeRate,
    headerExpanded,
    setHeaderExpanded,
    showHeaderCustomer,
    requireHeaderCustomer,
    customerId,
    customerCode,
    customerName,
    customerType,
    setCustomerType,
    representativeName,
    setCustomerId,
    setCustomerCode,
    setCustomerName,
    setRepresentativeName,
    customerPhone,
    setCustomerPhone,
    searchFieldClass,
    searchDisabled,
    reference,
    referenceCustomerName,
    setReference,
    setReferenceCustomerName,
    showAllocateBtn,
    setShowAllocateModal,
    showDetailObject,
    setShowDetailObject,
    headerCustomerFilterType,
    lineCustomerFilterType,
    showInvoiceGrid,
    isReadOnly,
    accountCode,
    accountName,
    setAccountCode,
    setAccountName,
    showCounterAccountHeader,
    counterAccountCode,
    counterAccountName,
    setCounterAccountCode,
    setCounterAccountName,
    description,
    setDescription,
    postingReasonCode,
    paymentChannelCode,
    postingReasonSearchConfig,
    paymentChannelSearchConfig,
    selectedPostingReason,
    selectedPaymentChannel,
    handlePostingReasonSelect,
    handlePostingReasonClear,
    handlePaymentChannelSelect,
    handlePaymentChannelClear,
    showAllowEditPostingCheckbox,
    allowEditPostingAccounts,
    handleAllowEditPostingAccountsChange,
    postingAccountsLocked,
    textareaClassName,
    textareaReadOnly,
    textareaDisabled,
    selectDisabled,
    handleRequestCustomerChange,
    customerSearchConfigOptions,
    showCustomerConfirm,
    showReceiptKindConfirm,
    handleReceiptKindConfirmChange,
    handleReceiptKindCancelChange,
    handleCustomerConfirmChange,
    handleCustomerCancelChange,
  } = vm;

  /** §8.10.3 — PT: Ngày + Loại + ĐT + TK; PC: Ngày + ĐT + TK (`cash-voucher-header-compact-map.md`) */
  const useCompactHeader = kind === 'receipt' || kind === 'payment';
  const accountSearchOptions = useAccountSearchAsOfDate(voucherDate);
  const accountSearchConfig = useMemo(
    () => createAccountSearchConfig(accountSearchOptions),
    [accountSearchOptions],
  );
  const postingReasonName = selectedPostingReason?.name ?? '';
  const paymentChannelName = selectedPaymentChannel?.name ?? '';
  const accountSearchDisabled = searchDisabled || postingAccountsLocked;

  const compact = useVoucherHeaderCompact({
    enabled: useCompactHeader,
    headerExpanded,
    styles: {
      field: styles.field,
      headerCompactHidden: styles.headerCompactHidden,
      headerCompactActive: styles.headerCompactActive,
    },
  });
  const formRowStyles = { row5: layout.row5 };
  const span2 = layout.spanCol2;
  const span3 = layout.spanCol3;
  const partnerColSpan = compact.isCompact ? layout.compactPartnerCol : span2;
  const headerSearchClass = [searchFieldClass, layout.lookupCodeMax150, layout.lookupDualInline]
    .filter(Boolean)
    .join(' ');
  const headerLookupSingleClass = searchFieldClass;

  const headerToggle = useCompactHeader ? (
    <button
      type="button"
      className={styles.headerToggleBtn}
      data-testid={tid(headerExpanded ? 'header-collapse' : 'header-expand')}
      aria-expanded={headerExpanded}
      onClick={() => setHeaderExpanded(v => !v)}
    >
      <span className={styles.headerToggleIcon} aria-hidden>
        <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
      </span>
      {headerExpanded ? labels.headerCollapse : labels.headerExpand}
    </button>
  ) : null;

  const sectionClass = [styles.section, viewSectionClass, compact.headerCompactSectionClass, layout.headerGrid5, compact.isCompact && layout.headerGrid5Compact]
    .filter(Boolean)
    .join(' ');

  const fieldsFlowClass = [styles.headerFieldsFlow, compact.isCompact && layout.headerFieldsFlowCompact].filter(Boolean).join(' ');
  return (
    <>
      <div
        className={sectionClass}
        id={tid('section-header')}
      data-testid={tid('section-header')}
    >
      <div className={styles.sectionTitleRow}>
        <h2 className={styles.sectionTitle}>{labels.sectionHeader}</h2>
        {headerToggle}
      </div>

      <div className={fieldsFlowClass}>
        <VoucherFormRow styles={formRowStyles} columns={5}>
          <div
            id={tid('field-voucherDate')}
            className={compact.fieldClass(compact.compactHideClass(true))}
            data-testid={tid('field-voucherDate')}
          >
            <label className={styles.label}>
              {labels.voucherDate}
              <RequiredMark />
            </label>
            <Input
              type="date"
              value={voucherDate}
              error={fieldErrors.voucherDate}
              onChange={e => {
                const v = e.target.value;
                setVoucherDate(v);
                patchHeaderFieldError('voucherDate', v);
              }}
              {...fieldLockProps}
            />
          </div>
          <div className={compact.fieldClass(compact.compactHideClass(true))}>
              <label className={styles.label}>{labels.receiptKind}</label>
              <Select
                data-testid={tid('field-receiptKind')}
                options={receiptKindOpts}
                value={receiptKind}
                onChange={(e: React.ChangeEvent<HTMLSelectElement>) => {
                  const newValue = e.target.value;
                  if (newValue !== receiptKind) {
                    setReceiptKindPendingChange(newValue);
                    setShowReceiptKindConfirm(true);
                  }
                }}
                disabled={selectDisabled}
              />
            </div>
          <div
            id={tid('field-paymentChannelCode')}
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-paymentChannelCode')}
          >
            <label className={styles.label}>{labels.paymentChannelCode}</label>
            <SearchInput
              config={paymentChannelSearchConfig}
              value={paymentChannelCode}
              primaryDisplay={formatAccountDisplay(paymentChannelCode, paymentChannelName)}
              onChange={handlePaymentChannelSelect}
              onClear={handlePaymentChannelClear}
              className={headerLookupSingleClass}
              showLabel={false}
              showSecondaryInput={false}
              disabled={searchDisabled}
              placeholder={ph('Chọn hình thức thanh toán...')}
            />
          </div>
          <div
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-voucherCode')}
          >
            <label className={styles.label}>{labels.voucherCode}</label>
            <Input value={voucherNumber} placeholder={ph('Tự động sinh')} {...staticFieldProps} />
          </div>
          <CurrencyPairField
            className={compact.fieldClass(compact.compactHideClass(false))}
            currencyCode={currencyCode}
            exchangeRate={exchangeRate}
            currencyOptions={currencyOptions}
            staticFieldProps={staticFieldProps}
            selectDisabled={selectDisabled}
            currencyLabel={labels.currency}
            exchangeRateLabel={labels.exchangeRate}
            testId={tid}
            pairRatio="4-2"
          />
        </VoucherFormRow>

        <VoucherFormRow styles={formRowStyles} columns={5}>
          {showHeaderCustomer && (
            <div
              id={tid('field-customerId')}
              className={compact.fieldClass(partnerColSpan, compact.compactHideClass(true))}
              data-testid={tid('field-customerId')}
            >
              <label className={[styles.label, layout.partnerFieldLabel].filter(Boolean).join(' ')} data-testid={tid('field-customerId-label')}>
                <span>{formatPartnerFieldLabel(labels.partnerSideLabel)}</span>
                {requireHeaderCustomer ? <RequiredMark /> : null}
                <CustomerTypeBadge
                  customerType={customerType}
                  data-testid={tid('field-customerId-type')}
                />
              </label>
              <CustomerSearchField
                testIdPrefix={tid('customer')}
                className={headerSearchClass}
                customerId={customerId}
                customerCode={customerCode}
                customerName={customerName}
                error={fieldErrors.customerId}
                defaultCustomerType={headerCustomerFilterType}
                searchConfigOptions={customerSearchConfigOptions}
                onSelect={c => {
                  handleRequestCustomerChange({
                    id: c.customerId,
                    code: c.code,
                    name: c.name,
                    customerType: c.customerType,
                  });
                }}
                onClear={() => {
                  setCustomerId('');
                  setCustomerCode('');
                  setCustomerName('');
                  setCustomerType('');
                  setCustomerPhone('');
                  patchHeaderFieldError('customerId', '');
                }}
                placeholder={ph(labels.partnerPlaceholder)}
                disabled={searchDisabled}
              />
            </div>
          )}
          <div
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-customerPhone')}
          >
            <label className={styles.label}>{labels.customerPhone}</label>
            <Input
              value={customerPhone}
              onChange={e => setCustomerPhone(e.target.value)}
              {...fieldLockProps}
            />
          </div>
          {showHeaderCustomer && (
            <div
              className={compact.fieldClass(compact.compactHideClass(false))}
              data-testid={tid('field-representativeName')}
            >
              <label className={styles.label}>{labels.representativeLabel}</label>
              <Input
                value={representativeName}
                onChange={e => setRepresentativeName(e.target.value)}
                {...fieldLockProps}
              />
            </div>
          )}
          <div
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-reference')}
          >
            <label className={styles.label}>{labels.reference}</label>
            <ContractSearchField
              singleField
              className={headerLookupSingleClass}
              contractCode={reference}
              customerName={referenceCustomerName}
              onSelect={(code, name) => {
                setReference(code);
                setReferenceCustomerName(name);
              }}
              onClear={() => {
                setReference('');
                setReferenceCustomerName('');
              }}
              disabled={searchDisabled}
              placeholder={ph('Nhập mã hợp đồng...')}
            />
          </div>
        </VoucherFormRow>

        <VoucherFormRow styles={formRowStyles} columns={5}>
          <div
            id={tid('field-postingReasonCode')}
            className={compact.fieldClass(compact.compactHideClass(false))}
            data-testid={tid('field-postingReasonCode')}
          >
            <label className={styles.label}>{labels.postingReasonCode}</label>
            <SearchInput
              config={postingReasonSearchConfig}
              value={postingReasonCode}
              primaryDisplay={formatAccountDisplay(postingReasonCode, postingReasonName)}
              onChange={handlePostingReasonSelect}
              onClear={handlePostingReasonClear}
              className={headerLookupSingleClass}
              showLabel={false}
              showSecondaryInput={false}
              disabled={searchDisabled}
              placeholder={ph('Chọn lý do định khoản...')}
            />
          </div>
          <div
            id={tid('field-accountCode')}
            className={compact.fieldClass(compact.compactHideClass(true))}
            data-testid={tid('field-accountCode')}
          >
            <label className={styles.label}>
              {labels.cashLabel}
              <RequiredMark />
            </label>
            <AccountSearchInput
              api={erpFinanceAccountSearchApi}
              config={accountSearchConfig}
              className={headerLookupSingleClass}
              value={accountCode}
              primaryDisplay={formatAccountDisplay(accountCode, accountName)}
              error={fieldErrors.accountCode}
              onChange={a => {
                setAccountCode(a.code);
                setAccountName(a.name);
                patchHeaderFieldError('accountCode', a.code);
              }}
              onClear={() => {
                setAccountCode('');
                setAccountName('');
                patchHeaderFieldError('accountCode', '');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder={ph('Mã hoặc tên TK...')}
              disabled={accountSearchDisabled}
            />
          </div>
          <div
            id={tid('field-description')}
            className={compact.fieldClass(span3, compact.compactHideClass(false))}
            data-testid={tid('field-description')}
          >
            <label className={styles.label}>{labels.description}</label>
            <VoucherDescriptionField
              data-testid={tid('field-description-input')}
              value={description}
              error={fieldErrors.description}
              placeholder={ph('Nhập diễn giải...')}
              className={textareaClassName}
              minRows={1}
              onChange={v => {
                setDescription(v);
                patchHeaderFieldError('description', v);
              }}
              readOnly={textareaReadOnly}
              disabled={textareaDisabled}
            />
          </div>
        </VoucherFormRow>

        {(showCounterAccountHeader || showAllowEditPostingCheckbox || fmLegacyCode) && (
          <VoucherFormRow styles={formRowStyles} columns={5}>
            {showCounterAccountHeader && (
              <div
                className={compact.fieldClass(compact.compactHideClass(false))}
                data-testid={tid('field-counterAccountCode')}
              >
                <label className={styles.label}>
                  {labels.lineThAccount}
                  <RequiredMark />
                </label>
                <AccountSearchInput
                  api={erpFinanceAccountSearchApi}
                  config={accountSearchConfig}
                  className={headerLookupSingleClass}
                  value={counterAccountCode}
                  primaryDisplay={formatAccountDisplay(counterAccountCode, counterAccountName)}
                  onChange={a => {
                    setCounterAccountCode(a.code);
                    setCounterAccountName(a.name);
                  }}
                  onClear={() => {
                    setCounterAccountCode('');
                    setCounterAccountName('');
                  }}
                  showLabel={false}
                  showSecondaryInput={false}
                  placeholder={ph('TK đối ứng...')}
                  disabled={accountSearchDisabled}
                />
              </div>
            )}
            {showAllowEditPostingCheckbox && (
              <div
                className={compact.fieldClass(compact.compactHideClass(false))}
                data-testid={tid('field-allowEditPostingAccounts')}
              >
                <Checkbox
                  label={labels.allowEditPostingAccounts}
                  checked={allowEditPostingAccounts}
                  onChange={e => handleAllowEditPostingAccountsChange(e.target.checked)}
                  disabled={selectDisabled}
                  data-testid={tid('field-allowEditPostingAccounts-cb')}
                />
              </div>
            )}
            {fmLegacyCode ? (
              <div
                className={compact.fieldClass(compact.compactHideClass(false))}
                data-testid={tid('field-legacyCode')}
              >
                <label className={styles.label}>{labels.legacyCode}</label>
                <Input value={fmLegacyCode} {...staticFieldProps} />
              </div>
            ) : null}
          </VoucherFormRow>
        )}

        {showAllocateBtn && (
          <VoucherFormRow styles={formRowStyles} columns={5}>
            <div className={compact.fieldClass(compact.compactHideClass(false))}>
              <Button
                variant="secondary"
                type="button"
                data-testid={tid('allocate-invoices-btn')}
                onClick={() => setShowAllocateModal(true)}
                disabled={isReadOnly}
              >
                {labels.allocateInvoices}
              </Button>
            </div>
          </VoucherFormRow>
        )}
      </div>
    </div>

      <Modal isOpen={showReceiptKindConfirm} onClose={handleReceiptKindCancelChange} title="Xác nhận thay đổi loại phiếu">
        <p>Bạn có chắc muốn đổi loại phiếu? Dữ liệu trên form sẽ được cập nhật theo loại phiếu mới.</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={handleReceiptKindCancelChange}>Hủy</Button>
          <Button variant="primary" onClick={handleReceiptKindConfirmChange}>Xác nhận</Button>
        </div>
      </Modal>

      <Modal isOpen={showCustomerConfirm} onClose={handleCustomerCancelChange} title="Xác nhận thay đổi khách hàng/nhà cung cấp">
        <p>Bạn có chắc muốn đổi khách hàng/nhà cung cấp? Dữ liệu liên quan sẽ được cập nhật theo khách hàng/nhà cung cấp mới.</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={handleCustomerCancelChange}>Hủy</Button>
          <Button variant="primary" onClick={handleCustomerConfirmChange}>Xác nhận</Button>
        </div>
      </Modal>
    </>
  );
};
